import type { TZDate } from '@date-fns/tz';
import { RefObject } from 'react';
import type { FormControlRef, TimeRangePickerRef } from '../../../forms/shared-types.js';
import type { TimeValue } from '../../types/time.js';
import type { TimeErrorKey, Precision } from '../shared.types.js';
/**
 * Keeps the time offset as ISO string to preserve precision.
 * Can be a single offset string for single date selection,
 * or an object with `from`/`to` offsets for range selection.
 * @internal
 */
export type StringTimeOffset = string | {
    from: string;
    to: string;
};
/**
 * Base state slice for the Calendar component.
 * This is the foundational store state that other time-related components extend.
 * @internal
 */
export type CalendarTimeframeState = {
    /** The currently selected calendar value - can be a single TimeValue for single-date selection, a range object for range selection, or null when cleared. */
    calendarValue: TimeValue | null | {
        from: TimeValue | null;
        to: TimeValue | null;
    };
    /** The minimum selectable date/time boundary. */
    min?: TimeValue | null;
    /** The maximum selectable date/time boundary. */
    max?: TimeValue | null;
    /** Whether the calendar field is required for form validation. */
    required?: boolean;
    /** The precision level for time selection (day-only or with time components). */
    precision?: Precision;
    /** Ref to the calendar DOM element for imperative access (focus, validation). */
    calendarRef: RefObject<FormControlRef<HTMLDivElement> | (Omit<FormControlRef<HTMLDivElement>, 'inputRef'> & Pick<TimeRangePickerRef<HTMLDivElement>, 'inputRef'>)>;
    /** Current validation error state for the calendar. */
    calendarError?: TimeErrorKey;
    /** Preserved time from the value to keep the time during calendar selection. */
    timeOffset?: StringTimeOffset;
};
/**
 * Actions slice for the Calendar component.
 * Defines the store actions available to manipulate calendar state.
 * @internal
 */
export type CalendarTimeframeStoreActions = {
    /** Updates the calendar value when a date is selected. Handles range logic internally. */
    setCalendarValue: (value: TZDate) => void;
};
/**
 * Combined Calendar store type (state + actions).
 * Use this when consuming the full Calendar store.
 * @internal
 */
export type CalendarTimeframeStore = CalendarTimeframeState & CalendarTimeframeStoreActions;
